INSERT INTO public.photos VALUES (25670, 'Calle de la Verâ”œâ”‚nica 1966', 'Captura desde la calle de la Verâ”œâ”‚nica de la antigua manzana de viviendas delimitada por las calles Don Jaime I (al fondo), Verâ”œâ”‚nica (derecha), y Valentâ”œآ،n Zabala (izquierda), cuando habâ”œآ،an comenzado las obras preparativas (maderos de las ventanas), previas a su derribo integral. A la izquierda, el edificio del Teatro Principal, fuera de plano y, en el suelo, el tendido viario del bucle que efectuaba la lâ”œآ،nea 13 "San Josâ”œآ®" , para volver a subir hacia esa direcciâ”œâ”‚n, desde la calle Eusebio Blasco. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Registro ES. 50297. AM 04.01.02.11 38137', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65234600, -0.87917300, '0101000020E6100000B2D6506A2F22ECBF95D6DF1280D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26621199525.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26621199525.webp', 'https://www.flickr.com/photos/zaragozaantigua/26621199525/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25674, 'Calle Don Jaime aâ”œâ–’os 20', 'Esquina de la calle de Don Jaime I con la de los Estâ”œآ®banes (izquierda). Allâ”œآ، se situaba el establecimiento Rived y Châ”œâ”‚liz, de los socios Miguel Rived y Antonio Châ”œâ”‚liz, fundado en 1901 y dedicado a laboratorio farmacâ”œآ®utico y fotogrâ”œأ­fico. En 1930, Châ”œâ”‚liz se desvinculâ”œâ”‚ del negocio. Fuente: www.facebook.com/photo.php?fbid=1330866140308827&set=...', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.65281400, -0.87912200, '0101000020E61000002A36E675C421ECBF7B2FBE688FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31595412102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31595412102.webp', 'https://www.flickr.com/photos/zaragozaantigua/31595412102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25675, 'Calle Estâ”œآ®banes 1925', '"San Gil. Zaragoza". Acuarela de Salvador de Azpiazu, 1925. Vista de la torre de la iglesia de San Gil desde la calle de los Estâ”œآ®banes. Le acompaâ”œâ–’a otro pequeâ”œâ–’o dibujo con personajes tâ”œآ،picos ante una casa palaciega. Fuente visual: AMZ.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65310300, -0.87967000, '0101000020E6100000D8B628B34126ECBFB2F50CE198D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32126588186.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32126588186.webp', 'https://www.flickr.com/photos/zaragozaantigua/32126588186/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25677, 'Calle Alta de San Pedro 1844', '"Patio de la Infanta", en la antigua casa de Zaporta. Al fondo, a la derecha, las monumentales escaleras de acceso a las plantas superiores. Fuente visual: "Recuerdos y Bellezas de Espaâ”œâ–’a. Obra destinada a dar a conocer sus monumentos, antigâ”œâ•‌edades y vistas pintorescas en lâ”œأ­minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompaâ”œâ–’adas de texto por P. Piferrer y J. M. Quadrado. Aragâ”œâ”‚n: Josâ”œآ® Marâ”œآ،a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CENTRO', 41.65291000, -0.87800700, '0101000020E61000001E17D522A218ECBF9D9D0C8E92D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34829405196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34829405196.webp', 'https://www.flickr.com/photos/zaragozaantigua/34829405196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25680, 'Calle de Don Jaime I 1964', 'Cortejo oficial y tradicional encabezado, sobre mula blanca, del tradicionalista Pedro Cantero Cuadrado durante la toma de posesiâ”œâ”‚n como nuevo arzobispo de Zaragoza, el dâ”œآ،a 16 de julio de 1964, bajo un sofocante calor. La imagen se ha tomado en la calle de Don Jaime I, en el tramo desde las calles de San Jorge y Casto Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez, al fondo, hasta la plaza de Ariâ”œâ–’o, a espaldas del fotâ”œâ”‚grafo. Tras el arzobispo, la comitiva figura encabezada, a caballo, por el alcalde Luis Gâ”œâ”‚mez Laguna y el teniente de alcalde Gregorio Sâ”œأ­nchez Morales, los gobernadores civil y militar, y demâ”œأ­s autoridades, incluyendo una representaciâ”œâ”‚n de Carriâ”œâ”‚n de los Condes, pueblo natal del nuevo responsable de la diâ”œâ”‚cesis zaragozana. A ambos lados de la calle, gente asomada a los balcones de edificios que aâ”œâ–’os despuâ”œآ®s serâ”œآ،an, los mâ”œأ­s, derribados y sustituidos, sobre todo en el lado de la izquierda, por modernos bloques. Al fondo, el inmueble del nâ”¬â•‘ 18, diseâ”œâ–’ado por Teodoro Râ”œآ،os Balaguer en 1935 como sede de la Câ”œأ­mara Oficial de Comercio e Industria. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65337200, -0.87839000, '0101000020E610000024456458C51BECBFA10F96B1A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45719418965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45719418965.webp', 'https://www.flickr.com/photos/zaragozaantigua/45719418965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25868, 'Teatro Principal 1922', 'Imagen capturada desde el escenario del Teatro Principal y orientada hacia el pâ”œâ•‘blico asistente a la funciâ”œâ”‚n benâ”œآ®fica organizada por los asilados del Hospicio Provincial, patrocinada por la Diputaciâ”œâ”‚n Provincial y celebrada el 29 de marzo de 1922 con el desinteresado concurso de las compaâ”œâ–’â”œآ،as de los teatros Principal, Circo y Parisiana. En la imagen, el patio de butacas aparece prâ”œأ­cticamente lleno de los asilados del Hospicio, mientras la escala social ya es otra en los palcos de autoridades, como es normal.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.65208000, -0.87926000, '0101000020E61000006DCA15DEE522ECBF1630815B77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50025722141.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50025722141.webp', 'https://www.flickr.com/photos/zaragozaantigua/50025722141/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25870, 'Teatro Principal 1912', 'Imagen capturada en el interior del Teatro Principal durante el ensayo de una escena del tercer acto del "vaudeville" o comedia titulada "Petit Cafâ”œآ®", obra de Tristâ”œأ­n Bernard adaptada por Juan Josâ”œآ® Cadenas y mâ”œâ•‘sica del maestro Licâ”œâ”‚, producida por Pepe Cadenas y representada por la Compaâ”œâ–’â”œآ،a Palma-Reig, cuyos titulares eran la actriz Enriqueta Palma y el actor Luis Reig. Esta obra era la de mayor â”œآ®xito de la temporada, de forma que algâ”œâ•‘n periâ”œâ”‚dico considerâ”œâ”‚ que mâ”œأ­s que "Petit Cafâ”œآ®", este serâ”œآ،a el "Cafâ”œآ® Ambos Mundos" del Teatro Principal en el sentido de que atraerâ”œآ،a a mucha parroquia. Esta fue una muy buena noticia para este coliseo municipal, que desde principios de siglo venâ”œآ،a viviendo unos aâ”œâ–’os muy complicados, con constantes cambios en los arriendos concertados con diversos empresarios teatrales y poca asistencia de pâ”œâ•‘blico. En setiembre de 1912 el arriendo recayâ”œâ”‚ en la razâ”œâ”‚n social de Juan Bautista Simâ”œâ”‚n, que conociâ”œâ”‚ un arranque de temporada muy malo tras una ruinosa campaâ”œâ–’a durante las fiestas del Pilar. La imagen muestra el escenario y el patio de butacas con el aspecto tras la importante reforma proyectada por el arquitecto Ricardo Magdalena a finales del siglo XIX, destacando el espacio destinado a la orquesta.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.65208000, -0.87926000, '0101000020E61000006DCA15DEE522ECBF1630815B77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53457794516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53457794516.webp', 'https://www.flickr.com/photos/zaragozaantigua/53457794516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25896, 'Calle de la Verâ”œâ”‚nica 1970', 'Trolebâ”œâ•‘s de la lâ”œآ،nea "Gâ”œأ­llego" en su Terminal de la calle de la Verâ”œâ”‚nica, en 1970. Al fondo a la izquierda, las traseras de la iglesia del Sagrado Corazâ”œâ”‚n. Fuente visual: www.facebook.com/photo.php?fbid=10203016137152960&set...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65202700, -0.87864400, '0101000020E6100000B4739A05DA1DECBFF38DE89E75D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085612780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085612780.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085612780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23290, 'Calle de Goya 1960', 'Imagen de la que fuera parte de la antigua y larguâ”œآ،sima calle de Contamina hasta que el bisturâ”œآ، urbanâ”œآ،stico la seccionâ”œâ”‚ en dos cuando fue abierta la nueva calle de Alfonso I. Asâ”œآ،, el tramo entre el Temple y la nueva Alfonso I, conservâ”œâ”‚ su nombre, mientras que el tramo desde Alfonso I, y hasta la calle de Santa Cruz, recibiâ”œâ”‚ el nombre de "Goya". Ese serâ”œآ،a su nombre durante casi un siglo, hasta que el cubrimiento del tramo urbano de las vâ”œآ،as del ferrocarril a Barcelona, hizo que el Ayuntamiento le transfiriera el nombre, elevado a la categorâ”œآ،a de "avenida". A esta callecita del casco antiguo se le otorgâ”œâ”‚, entonces, el nombre de otro pintor: Jusepe Martâ”œآ،nez, el principal pintor del barroco zaragozano. En la imagen, calle de Goya poco antes de ser redenominada "Jusepe Martâ”œآ،nez", desde su confluencia con la calle de Santa Cruz. En primer plano, el antiguo mojâ”œâ”‚n de piedra para impedir el paso a vehâ”œآ،culos. Al fondo, la calle Alfonso, y un poco antes, hacia la izquierda, la calle de las Vâ”œآ،rgenes, pues allâ”œآ، estuvo el antiguo "Real Colegio de las Vâ”œآ،rgenes", o de "Nâ”¬آ¬ Sâ”¬آ¬ del Socorro". Fuente visual: amable aportaciâ”œâ”‚n del Archivo personal de Pablo Valdâ”œآ®s.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65399600, -0.87909900, '0101000020E61000001F48DE399421ECBF7FDB1324B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19638170711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19638170711.webp', 'https://www.flickr.com/photos/zaragozaantigua/19638170711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25199, 'P.â”¬â•‘ de la Independencia 1933', 'Plano del proyecto de prolongaciâ”œâ”‚n del paseo de la Independencia realizado por el arquitecto municipal Miguel â”œأ¼ngel Navarro. Tras el proyecto de 1930 de reforma interior urbana de los arquitectos Zuazo y Derqui, que contemplaba una prolongaciâ”œâ”‚n del paseo denominada "mâ”œأ­xima", por la anchura de 25 metros prevista para el nuevo vial resultante hasta el paseo del Ebro, esta nueva propuesta de 1933 preveâ”œآ،a una anchura de 20 metros hasta la calle del Pilar, donde confluirâ”œآ،a con una nueva avenida de uniâ”œâ”‚n de las plazas de las catedrales. En la imagen, comparativa de planos entre la situaciâ”œâ”‚n de partida, en la parte superior, y el resultado previsto tras la radical intervenciâ”œâ”‚n, en la parte inferior. Este proyecto quedâ”œâ”‚ en suspenso, y al aâ”œâ–’o siguiente Miguel â”œأ¼ngel Navarro realizarâ”œآ،a el no menos radical proyecto de apertura de la nueva calle de San Vicente de Paâ”œâ•‘l, que sâ”œآ، serâ”œآ،a realizado. A mediados de la dâ”œآ®cada de los aâ”œâ–’os sesenta, tras la conversiâ”œâ”‚n del paseo de la Independencia en una autopista para trâ”œأ­fico rodado, volviâ”œâ”‚ a ponerse encima de la mesa de trabajo el proyecto de su prolongaciâ”œâ”‚n, aunque tampoco pasarâ”œآ،a de las musas al teatro urbanâ”œآ،stico municipal. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65394200, -0.87911900, '0101000020E6100000E659492BBE21ECBF8CBD175FB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36411653725.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36411653725.webp', 'https://www.flickr.com/photos/zaragozaantigua/36411653725/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25652, 'Tejados c.1925', 'Toma de tejados zaragozanos. En primer plano, edificio de la calle Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez 17. Al fondo, el Pilar y La Seo. En el centro, la iglesia de Santa Cruz con el tejado de la Lonja detrâ”œأ­s. La imagen estâ”œأ­ tomada desde las oficinas de la Compaâ”œâ–’â”œآ،a Telefâ”œâ”‚nica en la calle de Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez 20, que fueron sustituidas por las del paseo de la Independencia en 1927. Fuente visual: Fundaciâ”œâ”‚n Telefâ”œâ”‚nica', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65381600, -0.87950000, '0101000020E6100000BE9F1A2FDD24ECBFFFCC203EB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15086705335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15086705335.webp', 'https://www.flickr.com/photos/zaragozaantigua/15086705335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25685, 'Calle de Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez 1926', 'Imagen capturada desde cierta altura en los tejados de la calle de Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez y centrada en el singular remate del nâ”¬â•‘ 20 de ese vial, donde despuntaba la alâ”œأ­mbrica torrecilla del veterano Centro Telefâ”œâ”‚nico Urbano de Zaragoza. A la izquierda, la torre barroca y el cimborrio mudâ”œآ®jar de la catedral de la Seo. A la derecha, la torre de la iglesia de San Juan y San Pedro (antigua de San Juan el Viejo) junto a la torre de Santa Marâ”œآ،a Magdalena y su remate aâ”œâ–’adido en â”œآ®poca barroca. Estas instalaciones telefâ”œâ”‚nicas serâ”œآ،an desmanteladas con la entrada en funcionamiento de la nueva y moderna central sita en el paseo de la Independencia.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65385100, -0.87956000, '0101000020E610000013D55B035B25ECBF7CBABA63B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53029323105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53029323105.webp', 'https://www.flickr.com/photos/zaragozaantigua/53029323105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20905, 'La Escuela de las Vâ”œآ،rgenes 1531', 'La Escuela de las Vâ”œآ،rgenes, anâ”œâ”‚nimo, â”œâ”‚leo sobre tabla, c.1570. (DPZ). El cuadro reproduce la fundaciâ”œâ”‚n simbâ”œâ”‚lica del Colegio de las Vâ”œآ،rgenes de Zaragoza (1531), cuya primera sede estuvo en la Manterâ”œآ،a. En 1585 se trasladâ”œâ”‚ al palacio renacentista de la calle de las Botigas Fondas. En la escena, la propia Virgen Marâ”œآ،a se dirige a un grupo de muchachas con hâ”œأ­bito. Al fondo a la derecha, la primera rectora de la instituciâ”œâ”‚n, rezando ante un sagrario. Otras cuatro damas ilustres, detrâ”œأ­s del cuadro principal. Y a la izquierda, una puerta se abre a las calles de Zaragoza (tal vez la plaza de la Diputaciâ”œâ”‚n, junto a la Cuchillerâ”œآ،a), con algunos Diputados del Reino, patronos del Colegio. Fuente: ceres.mcu.es/', 1531, 1531, 1531, 'Siglo XIX', 'CENTRO', 41.65319300, -0.88316600, '0101000020E6100000670DDE57E542ECBFF27C06D49BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14924146817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14924146817.webp', 'https://www.flickr.com/photos/zaragozaantigua/14924146817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21008, 'Convento de Santa Fe c.1860', 'Convento de Santa Fe de Zaragoza. Valentâ”œآ،n Carderera. Lâ”œأ­piz y acuarela sobre papel, entre 1831 y 1880. Este "Ex monasterio de monjas" fue fundado en 1553 para acoger prostitutas, por lo que fue llamado "Convento de las Arrepentidas". Tras su uso como Museo, el edificio fue derribado en 1908, ampliâ”œأ­ndose asâ”œآ، la plaza Salamero. Fuente: "Viaje artâ”œآ،stico por Aragâ”œâ”‚n de Valentâ”œآ،n Carderera", Josâ”œآ® Marâ”œآ،a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciâ”œâ”‚n Lâ”œأ­zaro Galdiano, 2013.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65251300, -0.88444200, '0101000020E6100000C0AE264F594DECBF809BC58B85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14919266460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14919266460.webp', 'https://www.flickr.com/photos/zaragozaantigua/14919266460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21024, 'Puerta de la Audiencia 1860', '"Zaragoza: Porta de los Gigantes" Los mitolâ”œâ”‚gicos grandes personajes que flanquean el acceso, identificados habitualmente con Hâ”œآ®rcules y Teseo, presentan todavâ”œآ،a esos particulares tocados sobre la testa, que luego fueron eliminados, tal vez por una moda mâ”œأ­s severa y menos florida, durante la intervenciâ”œâ”‚n-restauraciâ”œâ”‚n dirigida por el arquitecto provincial Pedro Martâ”œآ،nez Sangrâ”œâ”‚s en 1862-64. Las dos figuras recostadas a ambos lados del frontâ”œâ”‚n cabecero, que parece ser que sustentaban el escudo de armas del conde de Morata, y el leâ”œâ”‚n del centro, tambiâ”œآ®n fueron retirados El de la derecha ya estâ”œأ­ casi descabezado. Fuente visual: Charles Clifford, en The Metropolitan Museum of Art', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65376200, -0.88344500, '0101000020E61000003012DA722E45ECBF0CAF2479AED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21974069784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21974069784.webp', 'https://www.flickr.com/photos/zaragozaantigua/21974069784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21059, 'Convento de Santa Fe 1878', 'Fotografâ”œآ،a del claustro del desaparecido convento de Santa Fe, en la plaza del mismo nombre (actual de Salamero), en su â”œآ®poca como Museo Provincial de Zaragoza y Academia de Bellas Artes (entre 1848 y 1896). Pueden verse las obras artâ”œآ،sticas expuestas en la galerâ”œآ،a superior, abierta al aire libre. En el extremo del rincâ”œâ”‚n del claustro asoma el piso superior del torretâ”œâ”‚n de ladrillo renacentista del ex-convento.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.65233400, -0.88381900, '0101000020E610000069AB92C83E48ECBFD10836AE7FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866310765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866310765.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866310765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
