INSERT INTO public.photos VALUES (21839, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1931', 'Imagen del antiguo nâ”¬â•‘ 17 del paseo de Ruiseâ”œâ–’ores, que fuera uno de los originales seis hotelitos proyectados por Manuel Isasi Isasmendi de este perifâ”œآ®rico paseo (adquirido por Sebastiâ”œأ­n Rodrâ”œآ،guez), ya habilitado temporalmente como "La Casa del Niâ”œâ–’o", un instituto nipiolâ”œâ”‚gico o internado para atenciâ”œâ”‚n y cuidado de la salud de niâ”œâ–’os impulsado por el doctor Fernando Cuenca. Este hotelito serâ”œآ،a luego reformado para ampliarlo, y finalmente derribado. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63611100, -0.88930100, '0101000020E6100000639AE95E2775ECBF1CD0D2156CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34902197960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34902197960.webp', 'https://www.flickr.com/photos/zaragozaantigua/34902197960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21108, 'Convento de Santa Fe 1889', '"Saragosse. Une galerie du musâ”œآ®e provincial". Imagen del claustro alto del antiguo convento de la Santa Fe de la Penitencia, o Arrepentidas, fundado en el siglo XVI en plena Morerâ”œآ،a como otra de las instituciones dedicadas al recogimiento de mujeres de "vida errada y pecaminosa". En el momento de la captura fotogrâ”œأ­fica, estas instalaciones eran utilizadas como "Academia de Bellas Artes", y "Museo Provincial de Pinturas", aunque tambiâ”œآ®n de piezas de escultura, y pedazos de arquitectura. En 1908 fue demolido para ensanchar viales y hacer mâ”œأ­s grande la plaza de Salamero. Sic transit gloria mundi. Fuente: J. Lâ”œآ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragâ”œâ”‚n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65269900, -0.88390400, '0101000020E6100000F6B6990AF148ECBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22550936450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22550936450.webp', 'https://www.flickr.com/photos/zaragozaantigua/22550936450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21124, 'Coso alto 1889', 'Imagen centrada en el gran edificio de la Audiencia, antigua casa de los Luna, en el Coso alto. A la izquierda, el arranque de la calle de Cerdâ”œأ­n. A la derecha, la calle de la Audiencia. La captura se ha realizado, posiblemente, desde la altura de la nueva sede de la Compaâ”œâ–’â”œآ،a de Telâ”œآ®fonos Urbanos de Zaragoza.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65369300, -0.88326000, '0101000020E6100000C1ADBB79AA43ECBFE34F5436ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34306656645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34306656645.webp', 'https://www.flickr.com/photos/zaragozaantigua/34306656645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21132, 'Patio de la Audiencia 1881', 'Grabado que reproduce parcialmente el patio del "Colegio de Procuradores de Zaragoza" sito en la antigua casa de los Luna, luego Morata, luego Perelada, y finalmente sede de la Audiencia Provincial, hasta el momento actual. Descansa sobre una de las columnas anilladas del lado sur del patio un paisano singular, mientras una sombra se proyecta en las escaleras del fondo, junto al ingreso principal, que a la izquierda se abre desde el Coso Alto.', 1881, 1881, 1881, 'Siglo XIX', 'CENTRO', 41.65414800, -0.88357300, '0101000020E61000008F1D54E23A46ECBF355F251FBBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47669864112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47669864112.webp', 'https://www.flickr.com/photos/zaragozaantigua/47669864112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21183, 'Coso alto 1890', 'Imagen de la Audiencia Territorial, entre la calle de Cerdâ”œأ­n, a la izquierda, y la calle de la Audiencia. En el nâ”¬â•‘ 3 del Coso, a la derecha, vista parcial de la "Gran Sastrerâ”œآ،a el Non-Plus-Ultra". Fuente visual: "Palacio de Los Lunas, hoy Audiencia Territorial", en أ”أ‡آ£Zaragoza Artâ”œآ،stica, Monumental e Histâ”œâ”‚ricaأ”أ‡أک, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91), a travâ”œآ®s de www.todocoleccion.net/', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65369300, -0.88326000, '0101000020E6100000C1ADBB79AA43ECBFE34F5436ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34192946841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34192946841.webp', 'https://www.flickr.com/photos/zaragozaantigua/34192946841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
