INSERT INTO public.photos VALUES (21426, 'Calle Azoque c.1915', 'Foto: Lucas Cepero. Fachada de la tienda de ultramarinos de Federico Figueras (calle de Azoque 110), que elaboraba su propios chocolates, de marca Los Hâ”œآ®roes, en su fâ”œأ­brica de la calle de Agustina de Aragâ”œâ”‚n 42-44. A la izquierda, esquina con la calle de la Soberanâ”œآ،a Nacional, hoy Doctor Val-Carreres. Fuente visual: Colecciâ”œâ”‚n particular.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65116300, -0.88476600, '0101000020E6100000899B53C90050ECBFC0AE264F59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32949236511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32949236511.webp', 'https://www.flickr.com/photos/zaragozaantigua/32949236511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21687, 'Coso Alto c.1930', 'En primer tâ”œآ®rmino, el edificio del nâ”œâ•‘mero 5 con la Droga Alfonso, donde habâ”œآ،a vivido Luis Buâ”œâ–’uel. Al fondo a la derecha, la sirena del Banco de Aragâ”œâ”‚n, instalada en octubre de 1924. Se sustituyâ”œâ”‚ por otra en el nâ”œâ•‘mero 5 de Teniente Coronel Valenzuela, en abril de 1959. Y ahâ”œآ، sigue. Fuente visual: Archivo Mariano Arribas, en www.todocoleccion.net', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65365100, -0.88304700, '0101000020E6100000D5963AC8EB41ECBFB5FF01D6AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14947218675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14947218675.webp', 'https://www.flickr.com/photos/zaragozaantigua/14947218675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21691, 'Los Gigantes en el Coso 1931', '1931. Los Gigantes de la Comparsa de Gigantes y Cabezudos de Zaragoza, en posiciâ”œâ”‚n de descanso en el Coso Alto, junto a la Audiencia. La calle del fondo es Cerdâ”œأ­n. Fuente: Miguel Marâ”œآ،n Chivite, Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65396200, -0.88380500, '0101000020E61000002A52616C2148ECBFD369DD06B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15057034392.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15057034392.webp', 'https://www.flickr.com/photos/zaragozaantigua/15057034392/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21751, 'Iris Park 1935', 'Imagen de las seâ”œâ–’oritas postulantes de la "Fiesta de la Flor" en el complejo festivo del "Iris Park", durante la celebraciâ”œâ”‚n ofrecida en su honor el 7 de junio por la Capitanâ”œآ،a General, y con asistencia de 400 personas. La "Fiesta de la Flor" consistâ”œآ،a en una colecta de carâ”œأ­cter benâ”œآ®fico-caritativo con la que se pretendâ”œآ،a sufragar la lucha antituberculosa en Zaragoza, del mismo modo que en otras ciudades. En estas fiestas, las clases altas autocelebraban y pregonaban su generosidad para con la pobre gente afectada por esta enfermedad. En Espaâ”œâ–’a, la tuberculosis tenâ”œآ،a entonces el carâ”œأ­cter de plaga (108 muertes por cada 100.000 habitantes, en 1935). En 1924, bajo la Dictadura de Primo de Rivera, se creâ”œâ”‚ el "Patronato de la Lucha Antituberculosa" como una iniciativa privada de carâ”œأ­cter benâ”œآ®fico que se nutrâ”œآ،a de colectas, donaciones, tâ”œâ”‚mbolas, fiestas, y espectâ”œأ­culos varios. Con la Segunda Repâ”œâ•‘blica, se tratâ”œâ”‚ de estatalizar la lucha de forma planificada, con dotaciâ”œâ”‚n presupuestaria pâ”œâ•‘blica suficiente, dando prioridad a la prevenciâ”œâ”‚n, con la construcciâ”œâ”‚n de nuevos sanatorios y ambulatorios, y con personal cualificado dentro de la Sanidad Nacional. Los cambios de orientaciâ”œâ”‚n del Gobierno aceleraron o retrasaron estas polâ”œآ،ticas, y el conflicto civil iniciado en 1936 abortâ”œâ”‚ el camino y empeorâ”œâ”‚ el problema, volviendo a la senda de la beneficiencia. Hasta 1951 la tasa de muertes por tuberculosis no volviâ”œâ”‚ a los niveles de antes de la guerra. Fuente: Foto Marâ”œآ،n Chivite, "Mundo Grâ”œأ­fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22028391171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22028391171.webp', 'https://www.flickr.com/photos/zaragozaantigua/22028391171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21779, 'La Audiencia 1930', 'Coso Alto con el edificio del antiguo palacio de los Luna. A la izquierda, la calle de las Escuelas Pâ”œآ،as. A la derecha, calle Azoque. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65398600, -0.88374500, '0101000020E6100000D61C2098A347ECBF5C0531D0B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22952299060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22952299060.webp', 'https://www.flickr.com/photos/zaragozaantigua/22952299060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
