INSERT INTO public.photos VALUES (21870, 'Iris Park 1932', 'Imagen con la planta del gran complejo de ocio Iris Park inaugurado en 1931 entre las calles de Azoque y Ramâ”œâ”‚n y Cajal, con la localizaciâ”œâ”‚n de sus principales espacios. Cuatro grandes edificios centralizaban su actividad: un cine -el mâ”œأ­s grande de Zaragoza en ese momento-, teatro, pista de patinaje y gran salâ”œâ”‚n de baile-restaurant. Otros espacios al aire libre completaban este lugar irrepetible, en pleno centro de la ciudad, funcional hasta comienzos de la dâ”œآ®cada de los aâ”œâ–’os cincuenta. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.65146500, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF8CBE823463D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36698411415.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36698411415.webp', 'https://www.flickr.com/photos/zaragozaantigua/36698411415/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21875, 'Iris Park c.1934', 'Imagen capturada en el interior del festivo recinto del Iris Park, posiblemente en la zona de terrazas al aire libre entre la Pista de Baile de Verbena, el Gran Teatro de Verano y el Salâ”œâ”‚n de Cine. Tras las dos casetas que centran la imagen, traseras edilicias de los nâ”œâ•‘meros impares de la calle de la Biblioteca. Fuente visual: foto Wamba, en www.todocoleccion.net/', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65146500, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF8CBE823463D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40013399385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40013399385.webp', 'https://www.flickr.com/photos/zaragozaantigua/40013399385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21904, 'Coso Alto 1939', 'Castiza imagen capturada en el Coso alto (con vista al fondo del tramo comprendido entre los inmuebles de los nâ”œâ•‘meros 8 al 26) durante el gran desfile organizado con motivo de la visita a Zaragoza del "Caudillo" y "Generalâ”œآ،simo" para celebrar la Fiesta de la Raza el 12 de octubre de 1939 ("Aâ”œâ–’o de la Victoria"). La fotografâ”œآ،a ha sido realizada durante el desfile ante el "Palacio de la Audiencia" en cuyos balcones estaban observantes las autoridades, de la "parte tâ”œآ،pica" del desfile, integrada por representantes de la regiâ”œâ”‚n aragonesa vestidos a la manera tradicionalista y centrada en los danzantes de Tauste formando su "famosa torre" o castillo humano. Ante ellos, la tribuna montada para representantes de corporaciones, sillas ocupadas por "Caballeros mutilados", y comisiones de los cuerpos de la Guarniciâ”œâ”‚n y de las corporaciones y entidades que no cupieron en la tribuna. Sobre el adoquinado firme, vâ”œآ،as por las que transitaban los tranvâ”œآ،as de las lâ”œآ،neas 2. "Madrid", 3. "Delicias" y 7. "Ayuntamiento-Portillo".', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.65383500, -0.88377700, '0101000020E6100000AE9FFEB3E647ECBF76FD82DDB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51683796008.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51683796008.webp', 'https://www.flickr.com/photos/zaragozaantigua/51683796008/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22089, 'Nuevo Teatro Iris 1955', 'Nuevo Teatro Iris de Zaragoza, dibujo de su tramoyista, Mariano Gimeno, 1955. Aspecto de la fachada del Teatro Iris de Zaragoza, poco despuâ”œآ®s de su inauguraciâ”œâ”‚n el 24 de febrero de 1955. Ese dâ”œآ،a se celebrâ”œâ”‚ un acto privado por la maâ”œâ–’ana, y por la tarde un espectâ”œأ­culo de corte baturrista titulado Raza Aragonesa. Al dâ”œآ،a siguiente, Rosario y su ballet de arte espaâ”œâ–’ol iniciaron allâ”œآ، su temporada, como se puede leer en el cartel reproducido. El edificio, de Josâ”œآ® de Yarza, con uso tambiâ”œآ®n de cine, se levantâ”œâ”‚ sobre el solar del antiguo teatro del mismo nombre que estuvo en pie entre 1931 y 1953 en el complejo de ocio Iris Park. En 1958 se le cambiâ”œâ”‚ el nombre por el de Teatro Fleta. Desde la dâ”œآ®cada de los 60 se dedicâ”œâ”‚ a la exhibiciâ”œâ”‚n de cine, hasta que cerrâ”œâ”‚ el 14 de enero de 2000, para ser posteriormente semiderruido. Fuente visual: www.elpais.com Fuente textual: Amparo Martâ”œآ،nez, Artigrama, 1999.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18964372634.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18964372634.webp', 'https://www.flickr.com/photos/zaragozaantigua/18964372634/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22215, 'Calle de Valenzuela 1959', 'Imagen centrada en el veterano Hotel Lafuente sito en la calle del Teniente Coronel Valenzuela, tras una reforma que le habâ”œآ،a conferido este luminoso aspecto moderno. A su izquierda, la nueva e imponente sede central del Banco de Aragâ”œâ”‚n. A su derecha, el inmueble del nâ”¬â•‘ 9. La escena estâ”œأ­ capturada desde el encuentro de la referida calle, antigua de la Morerâ”œآ،a, con la plaza de Salamero, antigua de la Santa Fe, con una leve vista de la esquina del colegio de las madres Escolapias, en primer tâ”œآ®rmino y a la izquierda. Fuente visual: AMZ', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65269900, -0.88310000, '0101000020E61000008A1F63EE5A42ECBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46182132844.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46182132844.webp', 'https://www.flickr.com/photos/zaragozaantigua/46182132844/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22278, 'Lola Flores 1962', '"Lola Flores asiste al estreno de "El balcâ”œâ”‚n de la Luna" en el Gran Teatro Fleta de Zaragoza el 4 de febrero de 1962 - Foto: Parâ”œآ،s (Zaragoza) - Gentileza de â”œأ¼ngel Villaverde Rubio (Zaragoza)" rafaelcastillejo.com', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65148800, -0.88513700, '0101000020E61000007D586FD40A53ECBF44DE72F563D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14981505086.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14981505086.webp', 'https://www.flickr.com/photos/zaragozaantigua/14981505086/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22477, 'Pl. de Salamero 1968', 'Imagen realizada por Joaquâ”œآ،n Alcâ”œâ”‚n Pueyo y centrada en el acceso al bar El Pozal, sito en la fachada meridional de la plaza de Salamero (antigua de Santa Fe), tramo entre la calle del Requetâ”œآ® Aragonâ”œآ®s (hacia la izquierda) y la del Azoque (hacia la derecha). Este establecimiento de bebidas espirituosas formaba parte del paisaje emocional de la plaza desde su apertura en 1922, y se consolidâ”œâ”‚ como puntual lugar de encuentro de destacadas personalidades de la intelectualidad de la â”œآ®poca, como artistas, escritores, toreros, et caetera. Pâ”œâ•‘blico en general y trabajadores constituâ”œآ،an el grueso de su parroquia hasta que cerrâ”œâ”‚ en los aâ”œâ–’os 80. Tras el derribo del antiguo edificio (nâ”œâ•‘meros 3-4 de la plaza) sobre su solar fue construido el actual bloque del nâ”¬â•‘ 1 de la calle Azoque. Llamativamente, en el momento de realizar esta captura la publicidad exterior mâ”œأ­s visible resultaba ser la de una bebida carbonatada inalcohâ”œâ”‚lica de origen norteâ”œâ–’o. Fuente visual: web.dpz.es/arscatalogi.es/', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65197800, -0.88397900, '0101000020E61000009F39EB538E49ECBF12DBDD0374D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34883020313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34883020313.webp', 'https://www.flickr.com/photos/zaragozaantigua/34883020313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22579, 'Audiencia 1977', 'Toma del tramo del Coso Alto a la altura del palacio de la Audiencia de Zaragoza, en 1977. Al fondo, manzana entre las calles Cerdâ”œأ­n y Escuelas Pâ”œآ،as, en demoliciâ”œâ”‚n. Fuente: www.facebook.com/photo.php?fbid=865591303474446&set=o...', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65383500, -0.88356200, '0101000020E610000094A0BFD02346ECBF76FD82DDB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15561899027.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15561899027.webp', 'https://www.flickr.com/photos/zaragozaantigua/15561899027/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22622, 'Calle Azoque 1977', 'Imagen de la antigua calle de Azoque mirando hacia lo que fue la plazuela de Luis Santâ”œأ­ngel, y el inmediato emboque hacia el Coso Alto. Tras los derribos y ensanches realizados a izquierda (calle Pignatelli, callejâ”œâ”‚n de Serâ”œâ”‚n desaparecido), y derecha (calle Palomeque), la calle Azoque parece haberse convertido en una triste calleja: es lo que sucede cuando se altera la escala y proporciones urbanas. Hasta este momento, y durante siglos, no parecâ”œآ،a problemâ”œأ­tico que este fuera el modelo urbanâ”œآ،stico de la zona. El problema comenzâ”œâ”‚ cuando hubo que comenzar a inventarse espacios donde no los habâ”œآ،a para que el vehâ”œآ،culo privado a motor de explosiâ”œâ”‚n, un reciâ”œآ®n llegado, pudiera moverse como si la milenaria ciudad le hubiera tocado en una rifa, y fuera suya. Al poco tiempo, la Avenida de Câ”œآ®sar Augusto se abrirâ”œأ­ paso por aquâ”œآ، a golpe de nuevos derribos, para consolidar una urbana autovâ”œآ،a desde el puente de Santiago, y hasta la puerta del Carmen, abriendo una trinchera de asfalto y trâ”œأ­fico rodado por la vieja Morerâ”œآ،a, jalonada ademâ”œأ­s por nuevos, modernos y enormes edificios residenciales. Al fondo, y a la derecha, aâ”œâ•‘n puede verse el remate de una de las torres del antiguo palacio de los Luna-Morata.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65361900, -0.88408800, '0101000020E61000004E27D9EA724AECBFA98592C9A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19785652132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19785652132.webp', 'https://www.flickr.com/photos/zaragozaantigua/19785652132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22664, 'Iglesia de Santiago 1971', 'Iglesia de Santiago el Mayor en una vista de su fachada principal capturada desde la plaza de Miguel Salamero. En primer tâ”œآ®rmino, restos de la manzana comprendida entre la calle del Azoque y la de San Ildefonso, al fondo, derribada para dar continuidad a la avenida Imperial y ampliar la calle del Doctor Gâ”œâ”‚mez Ulla (luego desaparecida). Aâ”œâ–’os despuâ”œآ®s, sobre estos solares se construirâ”œآ،a tambiâ”œآ®n un impactante bloque de oficinas comerciales.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65239100, -0.88438900, '0101000020E61000000B26FE28EA4CECBF359A5C8C81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22756748059.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22756748059.webp', 'https://www.flickr.com/photos/zaragozaantigua/22756748059/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22971, 'Teatro Fleta aâ”œâ–’os 90', 'Foto Gonzalo Bullâ”œâ”‚n. El teatro Fleta fue un edificio de Josâ”œآ® de Yarza construido en 1955 y usado casi exclusivamente como cine en sus â”œâ•‘ltimos aâ”œâ–’os. En el cambio de siglo posterior se derribâ”œâ”‚, dejando la fachada en pie.', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65163900, -0.88518800, '0101000020E610000005F9D9C87553ECBF2AE620E868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15009818245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15009818245.webp', 'https://www.flickr.com/photos/zaragozaantigua/15009818245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23207, 'Calle Morata 2010', 'Foto: Oliver Duch. Solar entre las calles de Morata (tras el fotâ”œâ”‚grafo) y Galo Ponte (a la izquierda). Albergarâ”œأ­ desde 2012 la sede de la Audiencia Provincial de Zaragoza, dejando al palacio de los Luna (derecha) como Tribunal Superior de Justicia de Aragâ”œâ”‚n. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.65446500, -0.88302800, '0101000020E61000002579AEEFC341ECBF36B05582C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32824462223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32824462223.webp', 'https://www.flickr.com/photos/zaragozaantigua/32824462223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23497, 'Coso Alto 1877', 'Bajo una intensa solanera de la segunda quincena del mes de junio y desde el resguardo de la altura relativa de la Casa de las Monas, una visual del Coso Alto que quita el aliento, desde la Audiencia, inmediata, hasta la plaza de la Constituciâ”œâ”‚n, al fondo, pasando por algunas de las aâ”œâ–’ejas casas de la alta nobleza indâ”œآ،gena.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65386700, -0.88359400, '0101000020E61000006C239EEC6646ECBF8177F2E9B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679887379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679887379.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679887379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23501, 'Portada de la Audiencia 1889', 'J. Lâ”œآ®vy et Cie, 1889 Puerta de de entrada del palacio de los Condes de Morata o de los Luna, sede de la Audiencia. Las figuras que la custodian a ambos lados son consideradas representaciones de Teseo y Hâ”œآ®rcules. El humorista Chas bautizâ”œâ”‚ a los gigantes como "Que te zumbo" y "Que te arreo":', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65396700, -0.88366000, '0101000020E610000049111956F146ECBFE5D4CE30B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14988388541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14988388541.webp', 'https://www.flickr.com/photos/zaragozaantigua/14988388541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23503, 'Palacio de Torresecas c.1859', 'Patio de la Casa de los Condes de Torres Secas en Zaragoza. Valentâ”œآ،n Carderera. 1832-1880. El palacio de Torresecas estaba enclavado en la calle Coso, en el actual nâ”¬â•‘ 5 (edificio de Drogas Alfonso), junto a un portillo abierto en 1271 en la muralla romana para acceder al Coso desde la plaza de San Felipe, que dio lugar a la calleja luego denominada Torresecas, cerrada posteriormente. En la imagen, dibujo del renacentista patio central del palacio de Torresecas. Fuente: "Viaje artâ”œآ،stico por Aragâ”œâ”‚n de Valentâ”œآ،n Carderera", Josâ”œآ® Marâ”œآ،a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciâ”œâ”‚n Lâ”œأ­zaro Galdiano, 2013.', 1859, 1859, 1859, 'Siglo XIX', 'CENTRO', 41.65365100, -0.88304700, '0101000020E6100000D5963AC8EB41ECBFB5FF01D6AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15572225330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15572225330.webp', 'https://www.flickr.com/photos/zaragozaantigua/15572225330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23504, 'Cabezudos y Gigantones 1872', 'Dibujo: Pradilla; grabado: Capuz. 1872. "Zaragoza. Fiestas del Pilar: los Cabezudos y Gigantones." Grabado de los gigantes, en su denominaciâ”œâ”‚n decimonâ”œâ”‚nica, y cabezudos, animando la calle en las fiestas mayores, delante del Palacio de Los Luna, al comienzo del Coso Alto. Hâ”œآ®rcules y Teseo, entoldados, casi sâ”œâ”‚lo se les ven las garrotas. A la izquierda, la calle de la Albarderâ”œآ،a que conduce a la plaza del Mercado. A la derecha, fuera de imagen, la Casa-Palacio de los Condes de Torresecas. Fuente: "La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana", Madrid, Aâ”œâ–’o XVI, nâ”¬â•‘ XXXIX, 16-10-1872.', 1872, 1872, 1872, 'Siglo XIX', 'CENTRO', 41.65396200, -0.88380500, '0101000020E61000002A52616C2148ECBFD369DD06B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15717871910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15717871910.webp', 'https://www.flickr.com/photos/zaragozaantigua/15717871910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
